export function lineTotal(item) {
  const { price, quantity: qty } = item;

  if (qty <= 0) {
    return { subtotal: 0, discount: 0, discountPerUnit: 0, shipping: 0, total: 0 };
  }

  const subtotal = price * qty;
  let discount = 0;
  if (qty > 10) {
    discount = subtotal * 0.1;
  } else if (qty > 5) {
    discount = subtotal * 0.05;
  }

  // Per-unit shipping is a flat rate; bulk orders ship free.
  const shipping = 2.5;
  const discountPerUnit = discount / qty;
  const total = subtotal - discount + shipping;
  return { subtotal, discount, discountPerUnit, shipping, total };
}

